text:
&-middle-blank {
  flex-grow: 1;
  display: flex;
  justify-content: space-around;
  z-index: 1;
  background: @color-fill-grey-inverse;
  background: var(--am-coupon-background-color, @color-fill-grey-inverse);
}

&-content {
  background: @color-fill-grey-inverse;
  background: var(--am-filter-content-bgc, @color-fill-grey-inverse);
  display: flex;
  flex-direction: column;
  overflow-x: hidden;
  overflow-y: scroll;
}

&:hover,
      &:focus {
        color: @nav-disabled-link-hover-color;
        text-decoration: none;
        background-color: transparent;
        cursor: @cursor-disabled;
        border-bottom: 1px solid @nav-disabled-link-base-hover-border-color;
      }

&:after {
  content: '\e6a1';
  display: inline-block;
  font-family: 'anticon';
  font-weight: bold;
  animation: loadingCircle 1s infinite linear;
  margin-top: 8px;
}

[data-article-id].cdm,
  .hl {
    margin-bottom: -1px;
    border: 1px solid @border-default;
    border-right-color: transparent !important;
    border-left-color: transparent !important;
    background-color: @default-bg;
  }

pre {
  box-shadow: none;
  color: @text-color;
  background: @inset-panel-background-color;
  border-radius: @component-border-radius;
  border: none;
  margin: 0;
}

article, aside, details, figcaption,
    figure, footer, header, hgroup, menu, nav,
    section, summary, main {
        display: block;
        .reset-box-model();
        .reset-focus();
        .reset-font();
    }

li.ui-draggable-dragging,
li.ui-sortable-helper {
  line-height: @component-line-height;
  height: @component-line-height;
  list-style: none;
  padding: 0 @component-padding;
  background: @background-color-highlight;
}

[data-tab-active="true"] {
  overflow: visible;
  height: auto;
  opacity: 1;
  display: inherit !important;
  transition: opacity .25s ease-in;
  margin: inherit !important;
}

> * ~ figcaption ~ *, // fix p/div incorrectly nested inside figcaption breaking out
  > img + p:last-child, // fix incorrectly using p instead of figcaption
  figcaption {
    margin-top: @spacing-sm;
    font-size: 0.875em;
    font-style: italic;
    line-height: 1.357;
  }

&-range-arrow {
  position: absolute;
  z-index: 1;
  box-sizing: content-box;
  margin-left: @input-padding-horizontal-base * 1.5;
  transition: left @animation-duration-slow ease-out;
  .roundedArrow(@arrow-size, 4px, @arrow-border-radius, var(--antd-arrow-background-color), @popover-arrow-box-shadow);
}

&-header {
  padding: @modal-header-padding;
  color: @text-color;
  background: @modal-header-bg;
  border-bottom: @modal-header-border-width @modal-header-border-style
    @modal-header-border-color-split;
  border-radius: @modal-border-radius @modal-border-radius 0 0;
}

&-btns {
  display: flex;
  justify-content: space-between;
  padding: 7px 8px;
  overflow: hidden;
  background-color: @table-filter-btns-bg;
  border-top: @border-width-base @border-style-base @table-border-color;
}

i.icon {
    width: 20px;
    height: 20px;
    -webkit-background-size: cover;
    background-size: cover;
    background-position: center;
    background-repeat: no-repeat;
}

input[type="range"]::-ms-track {
    width: 100%;
    height: 2px;
    cursor: pointer;
    background: transparent;
    border-color: transparent;
    color: transparent;
}

> span {
  @apply inline-block;
  @apply w-full;
  @apply whitespace-nowrap;
  @apply text-ellipsis;
  @apply overflow-hidden;
  @apply text-color-text-disabled;
}

&-lastMessage {
  font-size: 12px !important;
  color: var(--avmsg-muted) !important;
  white-space: nowrap !important;
  overflow: hidden !important;
  text-overflow: ellipsis !important;
  font-weight: 400 !important;
}

> li {
  display: inline-flex !important;
  align-items: center !important;
  margin: 0 !important;
  padding: 0 !important;
  list-style: none !important;
  flex-shrink: 0 !important;
}

article section.Pagination h3,
article section.Toolbar h3,
article section.ToolbarExample h3,
article section.LocalizationExample h3,
article section.LocalizationExample .kss-markup,
article section.ToolbarExample .kss-markup{
    display: none;
}

a.ui.labels .active.label:hover,
a.ui.active.label:hover {
  background-color: @labelActiveHoverBackgroundColor;
  border-color: @labelActiveHoverBackgroundColor;

  background-image: @labelActiveHoverBackgroundImage;
  color: @labelActiveHoverTextColor;
}

[data-tooltip]:before {
  opacity: 0;
  transform: rotate(45deg) scale(0) !important;
  transform-origin: center top;
  transition:
    all @tooltipDuration @tooltipEasing
  ;
}

li.hovered:not(.always-parent) + ol.children,
.elements-tree-outline ol.shadow-root,
li.selected:not(.always-parent) + ol.children {
  margin-left: 0 !important;
  border-width: 0 !important;
  border-left-style: none !important;
  -webkit-padding-start: 12px !important;
}

#counter-values-bar,
#memory-graphs-container .sidebar-tree-section,
.timeline-records-title,
.timeline-details-view-title {
  background-color: @global-toolbar !important;
  color: @global-text !important;
  text-shadow: none !important;
}

style + .text-prompt-editing,
.text-prompt-editing,
.editing {
  box-shadow: none !important;
  background-color: @global-background !important;
  outline: 1px solid @eh-editing-outline !important;
  color: @global-text !important;
}

caption + thead tr:first-child th,
  caption + thead tr:first-child td,
  colgroup + thead tr:first-child th,
  colgroup + thead tr:first-child td,
  thead:first-child tr:first-child th,
  thead:first-child tr:first-child td {
    border-top: 0;
  }

&__panel {
  padding: 0;
  width: @color-picker-panel-width;
  background: @color-picker-panel-background;
  border-top-left-radius: @color-picker-panel-radius;
  border-top-right-radius: @color-picker-panel-radius;
  user-select: none;
}

&--vertical {
  border-top: 0;
  display: inline-block;
  margin: @divider-vertical-margin;
  border-left: @divider-border-width solid @divider-border-color;
  height: @divider-vertical-height;
  vertical-align: middle;
}

&-viewer {
  display: flex;
  height: @datepicker-time-header-viewer-size;
  line-height: @text-line-height-base;
  align-items: center;
  justify-content: center;
  color: @text-color-primary;
}

&:hover,
  &:focus {
    #gradient .vertical( lighten(@background, 8%), @background);
    background-color: lighten(@background, 5%);
    color: @color;
    outline: none;
    text-decoration: none;
  }

svg {
    color              : transparent;
    background         : none;
    background-image   : var(--paddleIcon);
    background-position: center;
    background-repeat  : no-repeat;
    box-shadow         : none;
}
